`,e.jsx(t.p,{children:"ZCAM, by design, has no identity platform. There are no accounts, usernames, nor email addresses."}),`
`,e.jsxs(t.p,{children:["Every photo is signed using a key stored in the device's Secure Enclave. The key is ",e.jsx(t.strong,{children:"specific to the app"})," on that device and does ",e.jsx(t.strong,{children:"not"})," identify the person holding the phone"]}),`
`,e.jsx(t.p,{children:"This is pseudonymous by nature, the key is not used for anything other than Apple app attest. Even the C2PA key is not used for anything beyond signing valid C2PA manifests."}),`
